UPDATE about
SET
	name = #{name}
	,title = #{title}
	,github_url = #{githubUrl}
	,blog_url = #{blogUrl}
	,email_url = #{emailUrl}
	,is_published = #{isPublished}
WHERE
	id = #{id}
	AND admin_id = 1

UPDATE skill
SET name = #{name} ,description = #{description}
WHERE
	id = #{id}
	AND about_id = #{aboutId};

UPDATE section
SET title = #{title}, content = #{content}



			project_id = #{projectId}


			about_id = #{aboutId}



	AND id = #{id}

UPDATE image
SET ori_name = #{oriName}, saved_name = #{savedName}, extension = #{extension}
WHERE
	project_id = #{projectId}
	AND about_id = #{aboutId}
	AND id = #{id}

